format_number <- function(x, pretty = T) {
  if (pretty) format(x, big.mark = ",") else as.character(x)
}

should_skip <- function(flag) {
  if (flag == F) return("skip")
  return("run")
}

format_number <- function(x, pretty = TRUE) {
  if (isTRUE(pretty)) format(x, big.mark = ",") else as.character(x)
}
